const pos = $('Airtable - POs').first().json.records || [];
const invoices = $('Airtable - Invoices').first().json.records || [];
const inventory = $('Airtable - Inventory').first().json.records || [];
const budgets = $('Airtable - Budgets').first().json.records || [];
const occ = $('Airtable - Occupancy').first().json.records || [];

// ===== EXISTING: Anomaly Detection data =====
const negativeStock = inventory.filter(r => (r.fields['Current Stock'] || 0) < 0)
  .map(r => r.fields.Name + ': ' + r.fields['Current Stock'] + ' ' + (r.fields.Unit || '') + ', Par: ' + (r.fields['Par Level'] || 0))
  .join('\n') || 'None';

const todaysPOs = pos.map(r => (r.fields.po_number || 'N/A') + ': ' + (r.fields.vendor_name || 'Unknown') + ' €' + (r.fields.total_amount || 0)).join('\n') || 'None';
const todaysInvoices = invoices.map(r => '#' + (r.fields.invoice_number || 'N/A') + ': ' + (r.fields.seller_name || 'Unknown') + ' €' + (r.fields.invoice_amount || 0) + ' — ' + (r.fields.match_status?.name || r.fields.match_status || 'Pending')).join('\n') || 'None';
const budgetStatus = budgets.map(r => (r.fields['Item Category'] || 'Unknown') + ': ' + (r.fields['GL Code'] || '') + ' Budget: €' + (r.fields['Monthly Budget'] || 0)).join('\n') || 'No budget data';

// ===== NEW: Revenue Reconciliation data =====
// In testing phase, we construct sample revenue figures.
// When Abacus POS2 API arrives, these will come from live endpoints.
const today = new Date();
const businessDate = today.toISOString().split('T')[0];

// Get today's occupancy for revenue estimation
const todayOcc = occ.find(r => r.fields.Date === businessDate);
const roomsSold = todayOcc ? (r => r.fields['Rooms Sold'] || 0)(todayOcc) : Math.round(200 * 0.78);
const occPct = todayOcc ? ((todayOcc.fields['Occupancy %'] || 0) * 100) : 78;
const adr = 85; // sample ADR for Hotel Jadran

// Sample revenue figures (will be replaced by real POS/PMS data)
const roomRevenue = roomsSold * adr;
const fbRevenue = Math.round(roomsSold * 28); // ~€28 F&B per occupied room
const otherRevenue = Math.round(roomsSold * 4.5); // spa, parking, etc
const totalRevenue = roomRevenue + fbRevenue + otherRevenue;

// Sample collections (normally from CC batch + cash + city ledger)
const ccTotal = Math.round(totalRevenue * 0.87); // 87% CC
const cashTotal = Math.round(totalRevenue * 0.10); // 10% cash
const cityLedger = totalRevenue - ccTotal - cashTotal; // remainder

// Sample voids/comps
const voidCompData = [
  { type: 'void', item: 'Biftek na žaru', amount: 32, employee: 'Marko P.', authorized_by: 'Šef sale', reason: 'Pogrešna narudžba', timestamp: businessDate + 'T19:45:00' },
  { type: 'comp', item: 'Desert — Panna Cotta x2', amount: 18, employee: 'Ana S.', authorized_by: 'Menadžer restorana', reason: 'Kompenzacija za kašnjenje', timestamp: businessDate + 'T21:30:00' }
];

// Sample no-show data
const noshowData = [
  { reservation_id: 'RES-2026-' + Math.floor(Math.random()*9000+1000), guest_name: 'Schmidt, Thomas', room_type: 'Superior Double', rate: 95, charged: true, charge_amount: 95 }
];

return [{ json: {
  // Existing anomaly data
  scan_date: businessDate,
  negative_stock_items: negativeStock,
  has_negative_stock: inventory.some(r => (r.fields['Current Stock'] || 0) < 0),
  todays_pos_formatted: todaysPOs,
  todays_invoices_formatted: todaysInvoices,
  budget_status_formatted: budgetStatus,
  total_pos: pos.length,
  total_invoices: invoices.length,
  // NEW: Revenue reconciliation data for Prompt 15
  business_date: businessDate,
  rooms_sold: roomsSold,
  occupancy_pct: occPct,
  adr: adr,
  room_revenue: roomRevenue,
  restaurant_sales: Math.round(fbRevenue * 0.65),
  bar_sales: Math.round(fbRevenue * 0.25),
  room_service_sales: Math.round(fbRevenue * 0.10),
  total_fb: fbRevenue,
  spa_revenue: Math.round(otherRevenue * 0.5),
  parking_revenue: Math.round(otherRevenue * 0.3),
  other_misc: Math.round(otherRevenue * 0.2),
  total_other: otherRevenue,
  total_revenue: totalRevenue,
  cc_total: ccTotal,
  cash_total: cashTotal,
  city_ledger_total: cityLedger,
  void_comp_data: JSON.stringify(voidCompData),
  noshow_data: JSON.stringify(noshowData)
} }];

// Parse Prompt 8 anomaly result and store for later merge
const response = $input.first().json;
const content = response.choices[0].message.content;
let parsed;
try {
  parsed = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch(e) {
  parsed = { anomalies_found: 0, anomalies: [], summary: 'Greška u parsiranju Prompt 8 rezultata: ' + e.message, all_clear: true };
}

// Pass through aggregate data + anomaly result
const agg = $('Code - Aggregate Data').first().json;
return [{ json: { ...agg, anomaly_result: parsed } }];

// Build Prompt 15 Revenue Reconciliation input
const d = $input.first().json;

const systemPrompt = `Ti si AI noćni auditor za Hotel Jadran, hotel sa 200 soba u Budvi, Crna Gora. Svake noći obavljaš reviziju dnevnih prihoda uspoređujući podatke iz više izvora.

You MUST respond with valid JSON only. No markdown code blocks, no backticks, no explanation outside the JSON. Raw JSON only.

Klasifikacija neslaganja:
- Balanced: razlika = €0
- Minor Discrepancy: razlika < €50 ILI < 0.5% ukupnog prihoda
- Major Discrepancy: razlika >= €50 I >= 0.5% ukupnog prihoda
- Unbalanced: ne može se uskladiti — nedostaju podaci ili sistemska greška

Output JSON format:
{"business_date": "YYYY-MM-DD", "reconciliation_status": "Balanced|Minor Discrepancy|Major Discrepancy|Unbalanced", "total_revenue": 0, "total_collections": 0, "discrepancy_amount": 0, "revenue_breakdown": {"rooms": 0, "fb": 0, "other": 0}, "collections_breakdown": {"credit_card": 0, "cash": 0, "city_ledger": 0}, "void_comp_audit": {"total_voids": 0, "total_comps": 0, "total_amount": 0, "flags": [], "all_authorized": true}, "noshow_audit": {"total_noshows": 0, "all_charged": true, "uncharged": [], "total_noshow_revenue": 0}, "anomalies": [], "ai_summary": "BCS tekst 2-4 rečenice", "requires_attention": false, "attention_items": []}`;

const userPrompt = `Poslovni datum: ${d.business_date}
Hotel: Hotel Jadran (200 soba)
Popunjenost: ${d.occupancy_pct}% (${d.rooms_sold} soba)

=== PRIHODI OD SOBA (PMS) ===
Prodane sobe: ${d.rooms_sold}
Prosječna cijena (ADR): €${d.adr}
Ukupan prihod od soba: €${d.room_revenue}

No-show rezervacije:
${d.noshow_data}

=== F&B PRIHODI (POS) ===
Restoran: €${d.restaurant_sales}
Bar: €${d.bar_sales}
Room service: €${d.room_service_sales}
Ukupno F&B: €${d.total_fb}

=== OSTALI PRIHODI ===
Spa: €${d.spa_revenue}
Parking: €${d.parking_revenue}
Ostalo: €${d.other_misc}
Ukupno ostalo: €${d.total_other}

=== KREDITNE KARTICE ===
Ukupno CC: €${d.cc_total}

=== GOTOVINA ===
Ukupno gotovina: €${d.cash_total}

=== CITY LEDGER ===
Korporativna fakturiranja: €${d.city_ledger_total}

=== STORNO I POPUSTI ===
${d.void_comp_data}

Izvrši kompletno usklađivanje i reviziju.`;

return [{
  json: {
    ...d,
    recon_request: {
      model: 'kimi-k2.5',
      max_tokens: 2000,
      thinking: { type: 'disabled' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    }
  }
}];

// Parse Prompt 15 result
const response = $input.first().json;
const content = response.choices[0].message.content;
let recon;
try {
  recon = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch(e) {
  recon = {
    business_date: new Date().toISOString().split('T')[0],
    reconciliation_status: 'Pending Data',
    total_revenue: 0, total_collections: 0, discrepancy_amount: 0,
    revenue_breakdown: { rooms: 0, fb: 0, other: 0 },
    collections_breakdown: { credit_card: 0, cash: 0, city_ledger: 0 },
    void_comp_audit: { total_voids: 0, total_comps: 0, total_amount: 0, flags: [], all_authorized: true },
    noshow_audit: { total_noshows: 0, all_charged: true, uncharged: [], total_noshow_revenue: 0 },
    anomalies: [],
    ai_summary: 'Greška u parsiranju Prompt 15: ' + e.message,
    requires_attention: true,
    attention_items: ['Provjeriti Prompt 15 output format']
  };
}

// Get the aggregate data (which includes anomaly_result) from upstream
const agg = $('Code - Build Recon Input (Prompt 15)').first().json;

return [{ json: { ...agg, recon_result: recon } }];

// Combine Prompt 8 (anomaly) + Prompt 15 (reconciliation) into one Slack report
const data = $input.first().json;
const anomaly = data.anomaly_result;
const recon = data.recon_result;

let report = '🔍 *NOĆNI SCAN — ' + data.scan_date + '*\n\n';

// ===== SECTION 1: Anomaly Detection =====
report += '━━━ ANOMALIJE (Prompt 8) ━━━\n';
if (anomaly.all_clear) {
  report += '✅ Sve čisto — nema detektovanih anomalija.\n';
  if (anomaly.summary) report += anomaly.summary + '\n';
} else {
  report += '⚠️ ' + anomaly.anomalies_found + ' anomalija detektovano:\n\n';
  for (const a of (anomaly.anomalies || [])) {
    const icon = a.severity === 'HIGH' ? '🔴' : a.severity === 'MEDIUM' ? '🟡' : '🟢';
    report += icon + ' *' + a.type + '* — ' + a.description + '\n  Akcija: ' + a.recommended_action + '\n\n';
  }
  if (anomaly.summary) report += anomaly.summary + '\n';
}

// ===== SECTION 2: Revenue Reconciliation =====
report += '\n━━━ NOĆNI AUDIT (Prompt 15) ━━━\n';
const statusIcon = recon.reconciliation_status === 'Balanced' ? '✅' :
  recon.reconciliation_status === 'Minor Discrepancy' ? '🟡' : '🔴';

report += statusIcon + ' Status: *' + recon.reconciliation_status + '*\n';
report += '   Prihod: €' + (recon.total_revenue || 0).toLocaleString('de-DE', {minimumFractionDigits: 2}) + 
  ' | Naplata: €' + (recon.total_collections || 0).toLocaleString('de-DE', {minimumFractionDigits: 2}) + '\n';

if (recon.discrepancy_amount > 0) {
  report += '   Razlika: €' + recon.discrepancy_amount.toLocaleString('de-DE', {minimumFractionDigits: 2}) + '\n';
}

if (recon.void_comp_audit && !recon.void_comp_audit.all_authorized) {
  report += '\n🔍 *SUMNJIVI STORNO/POPUSTI:*\n';
  for (const flag of (recon.void_comp_audit.flags || [])) {
    report += '   • ' + flag + '\n';
  }
}

if (recon.noshow_audit && !recon.noshow_audit.all_charged) {
  report += '\n⚠️ *NENAPLAĆENI NO-SHOW:*\n';
  for (const ns of (recon.noshow_audit.uncharged || [])) {
    report += '   • ' + ns + '\n';
  }
}

if (recon.ai_summary) {
  report += '\n' + recon.ai_summary + '\n';
}

if (recon.requires_attention && (recon.attention_items || []).length > 0) {
  report += '\n📋 *POTREBNE AKCIJE:*\n';
  for (const item of recon.attention_items) {
    report += '   • ' + item + '\n';
  }
}

// Tag people if issues found
const hasIssues = !anomaly.all_clear || recon.requires_attention || recon.reconciliation_status !== 'Balanced';
if (hasIssues) {
  report += '\n@zoran';
}

// Build audit trail entry
const auditDetails = [];
if (!anomaly.all_clear) auditDetails.push(anomaly.anomalies_found + ' anomalija');
auditDetails.push('Recon: ' + recon.reconciliation_status);
if (recon.discrepancy_amount > 0) auditDetails.push('Razlika: €' + recon.discrepancy_amount.toFixed(2));

const auditBody = JSON.stringify({ records: [{ fields: {
  reference_id: 'ANOMALY-' + data.scan_date,
  event_type: 'ANOMALY_DETECTED',
  actor: 'System',
  details: auditDetails.join('. ')
} }] });

return [{ json: {
  report_text: report,
  audit_body: auditBody,
  has_issues: hasIssues,
  recon_result: recon,
  business_date: data.business_date
} }];
